import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';

const REGIONS = ['서울', '경기', '인천', '부산', '대구', '기타'];
const AGE_GROUPS = ['10대', '20대', '30대', '40대', '50대 이상'];
const SKILL_LEVELS = ['초보', '중급', '고수'];

function PostForm() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [form, setForm] = useState({
    title: '',
    content: '',
    region: '',
    age_group: '',
    skill_level: '',
  });
  const isEdit = !!id;

  useEffect(() => {
    if (isEdit) {
      fetch(`/api/posts/${id}`)
        .then(res => res.json())
        .then(data => setForm({
          title: data.post.title,
          content: data.post.content,
          region: data.post.region,
          age_group: data.post.age_group,
          skill_level: data.post.skill_level,
        }));
    }
    // eslint-disable-next-line
  }, [id]);

  const handleChange = e => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async e => {
    e.preventDefault();
    const method = isEdit ? 'PUT' : 'POST';
    const url = isEdit ? `/api/posts/${id}` : '/api/posts';
    await fetch(url, {
      method,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(form)
    });
    navigate('/posts');
  };

  return (
    <div style={{ maxWidth: 500, margin: '40px auto', background: '#fff', borderRadius: 12, boxShadow: '0 2px 8px #bbb', padding: 32 }}>
      <h2 style={{ marginBottom: 24 }}>게시글 작성</h2>
      <form onSubmit={handleSubmit}>
        <div style={{ display: 'flex', gap: 8, marginBottom: 24 }}>
          <select name="region" value={form.region} onChange={handleChange} required style={{ flex: 1, padding: 8, borderRadius: 8, border: '1px solid #ccc' }}>
            <option value="">지역</option>
            {REGIONS.map(r => <option key={r} value={r}>{r}</option>)}
          </select>
          <select name="age_group" value={form.age_group} onChange={handleChange} required style={{ flex: 1, padding: 8, borderRadius: 8, border: '1px solid #ccc' }}>
            <option value="">연령대</option>
            {AGE_GROUPS.map(a => <option key={a} value={a}>{a}</option>)}
          </select>
          <select name="skill_level" value={form.skill_level} onChange={handleChange} required style={{ flex: 1, padding: 8, borderRadius: 8, border: '1px solid #ccc' }}>
            <option value="">실력</option>
            {SKILL_LEVELS.map(s => <option key={s} value={s}>{s}</option>)}
          </select>
        </div>
        <div style={{ marginBottom: 20 }}>
          <input name="title" value={form.title} onChange={handleChange} placeholder="제목" style={{ width: '100%', fontSize: 18, padding: 10, borderRadius: 8, border: '1px solid #ccc' }} required />
        </div>
        <div style={{ marginBottom: 32 }}>
          <textarea name="content" value={form.content} onChange={handleChange} rows={8} placeholder="내용을 입력하세요" style={{ width: '100%', fontSize: 16, padding: 10, borderRadius: 8, border: '1px solid #ccc', resize: 'vertical' }} required />
        </div>
        <button type="submit" style={{ width: '100%', background: '#1976d2', color: '#fff', fontWeight: 600, fontSize: 18, border: 'none', borderRadius: 10, padding: '14px 0', cursor: 'pointer', boxShadow: '0 2px 8px #b0c4de' }}>
          글 작성
        </button>
      </form>
    </div>
  );
}

export default PostForm;
